45→    boolean maybePunctuate(final long timestamp, final PunctuationType type, final ProcessorNodePunctuator processorNodePunctuator) {
46→        synchronized (pq) {
47→            boolean punctuated = false;
48→            PunctuationSchedule top = pq.peek();
49→            while (top != null && top.timestamp <= timestamp) {
50→                final PunctuationSchedule sched = top;
51→                pq.poll();
52→
53→                if (!sched.isCancelled()) {
54→                    processorNodePunctuator.punctuate(sched.node(), timestamp, type, sched.punctuator());
55→                    // sched can be cancelled from within the punctuator
56→                    if (!sched.isCancelled()) {
57→                        pq.add(sched.next(timestamp));
58→                    }
59→                    punctuated = true;
60→                }
61→
62→
63→                top = pq.peek();
64→            }
65→
66→            return punctuated;
67→        }
